var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"부단장님. 소대 편성 및 작전 준비를 끝마쳤습니다.","JPN":"副団長。小隊編成および作戦の準備が終わりました。","ENG":"Deputy, all squads have been organized and mission prep is complete.","TWN":"副團長，已經完成小隊編成及作戰準備。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"부디 명령을 하달해 주시죠.","JPN":"どうかご命令を。","ENG":"We are awaiting your orders.","TWN":"請下達命令吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전 인원, 함선에 탑승 및 권역 감시 상태를 유지해주세요.","JPN":"全員、艦船に搭乗し圏域監視状態を維持してください。","ENG":"Have all units board the ship and maintain regional surveillance.","TWN":"全體人員，請保持登艦及區域監視狀態。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"지체할 이유는 없으니 즉시 현장으로 출발하겠습니다.","JPN":"遅らせる理由はありませんので、ただちに現場に向かいます。","ENG":"There's no reason to delay. We'll depart for the site immediately.","TWN":"沒有理由拖延，我會立即出發前往現場。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"예! 알겠습니다!","JPN":"はい！　かしこまりました！","ENG":"Yes, ma'am!","TWN":"是！明白！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그런 몸으로 정말 괜찮겠나요, 피오네 경?","JPN":"本当にその体で大丈夫ですか？　フィオネ卿。","ENG":"Are you sure you're up for this in your condition, Dame Fione?","TWN":"這樣的身體真的沒問題嗎，菲奧尼卿？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"걱정하시는 것은 이해하나, 가치판단을 가리지 못할 만큼 판단이 흐려진 것은 아닙니다.","JPN":"ご心配は理解できますが、価値判断ができないほど判断力が低下しているわけではありません。","ENG":"I understand your concern, but my judgment isn't so clouded that I'd ignore reason.","TWN":"我理解你的擔憂，但我的判斷並沒有模糊到無法分辨價值判斷的程度。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"무엇보다 지휘권을 지닌 인원의 작전 편제는 필수적이고요.","JPN":"なにより、指揮権を持っている人員の作戦編制は必須です。","ENG":"Besides, having a commanding officer directly manage the operation is essential.","TWN":"最重要的是，擁有指揮權的人員的作戰編制是必不可少的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"죄송해요. 저도 힘이 되어드리고 싶지만…….","JPN":"申し訳ありません。私も力になりたいのですが……","ENG":"I'm sorry. I wish I could be of more help...","TWN":"對不起。我也想幫上忙，但是……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"원로원의 동의 없는 우발적인 행동은 다시금 기사단에 부정적인 결과를 가져올 겁니다.","JPN":"元老院の同意のない突然の行動は、再び騎士団に否定的な結果をもたらすでしょう。","ENG":"Any rash actions without the Council's approval would only harm the Order again.","TWN":"沒有元老院的同意，突發行動將再次給騎士團帶來負面結果。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경이 저희의 뒤를 봐주시는 것은, 무엇보다도 큰 힘이 되죠.","JPN":"メデイア卿が支持してくださるだけで、とても心強いです。","ENG":"Having you watching our backs is more valuable than anything else, Dame Medea.","TWN":"美狄亞在背後支持我們，這比什麼都更有力量。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"레드시프트의 습격에 대비해 본부에도 인원은 남아야 하니, 현재의 구성이 합리적입니다.","JPN":"レッドシフトの襲撃に備えて本部にも残る人員が必要ですので、この構成が合理的です。","ENG":"We still need to leave personnel at HQ in case of another Red Shift attack. This setup is the most practical.","TWN":"為了應對紅移的襲擊，總部也需要留人，所以目前的配置是合理的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……어떤 상황에서든, 살아야 그 다음이 있는 법입니다.","JPN":"……どんな状況であっても、まずは生き残らないと次はありません。","ENG":"...No matter the situation, you have to survive if you want to see what comes next.","TWN":"……無論在什麼情況下，只有活著才有未來。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"잊지 마세요, 피오네 경.","JPN":"お忘れなく、フィオネ卿。","ENG":"Don't forget that, Dame Fione.","TWN":"不要忘記，菲奧尼卿。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예. 명심하겠습니다.","JPN":"はい。承知いたしました。","ENG":"Understood. I won't forget.","TWN":"是！我明白了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"부단장님. 전 인원, 탑승 완료했습니다!","JPN":"副団長。全員、搭乗完了です！","ENG":"Deputy! All units are aboard!","TWN":"副團長，全員已搭乘完畢！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경. 그럼 저도 이만…….","JPN":"メデイア卿。それでは私も……","ENG":"Then I'll be off, Dame Medea...","TWN":"美狄亞。那我也先行告辭……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 그전에 잠시 괜찮을까요?","JPN":"あ、その前に少しいいでしょうか？","ENG":"Ah, before you go, could I have a moment with you?","TWN":"啊，在此之前可以打擾一下嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예?","JPN":"え？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메, 메데이아 경?","JPN":"メ、メデイア卿？","ENG":"D-Dame Medea?","TWN":"美、美狄亞？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"후후. 무사히 다녀오라는 의미의 포옹이에요.","JPN":"ふふ。無事に帰っていらっしゃいのハグです。","ENG":"Haha. Just a hug to wish you a safe return.","TWN":"呵呵。這是祝你平安歸來的擁抱喔。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"제가 이렇게까지 했으니 지면 안 되는 거 알죠?","JPN":"私がここまでしましたから、負けてはいけませんよ？","ENG":"Now that I've done this, you know you can't lose, right?","TWN":"我都做到這個地步了，你知道不能輸吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……네. 물론입니다.","JPN":"……はい、もちろんです。","ENG":"...Of course. I won't.","TWN":"……是的。當然。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다녀오겠습니다, 메데이아 경.","JPN":"行ってきます、メデイア卿。","ENG":"I'll see you when I get back, Dame Medea.","TWN":"那我走了，美狄亞。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"휴우. 들키는 줄 알고 애 떨어지는 줄 알았네.","JPN":"ふう。バレるかと思って緊張したわ。","ENG":"Whew. Thought for sure she was going to catch on.","TWN":"呼，差點被發現，真是嚇死我了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"막무가내도 이런 막무가내가 없지. 대체 누구 머리에서 나온 작전이야, 이거?","JPN":"かなり無理やりだったわね。いったい誰がこんな作戦考えたのよ？","ENG":"Seriously, this plan is ridiculous. Who came up with this mess?","TWN":"這簡直是胡來，哪有這麼胡來的。到底是誰想出的這個作戰計畫？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"잘 됐네. 그럼 <color=#ffd34c>그쯤에서</color> 합류하자고.","JPN":"ちょうどよかったわ。じゃあ、<color=#ffd34c>そこら辺で</color>合流しましょう。","ENG":"Perfect. I'll meet you <color=#ffd34c>there</color>, then.","TWN":"太好了！那我們就在那邊會合吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"방해되지 않게 <color=#ffd34c>눈치 챙기는 것</color>도 잊지 마라?","JPN":"邪魔にならないように、<color=#ffd34c>空気読みなさい</color>よ？","ENG":"And hey, don't forget to <color=#ffd34c>read the room</color> and not to get in my way, all right?","TWN":"別忘了察言觀色，不要妨礙到別人喔？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"옛 코드 워드를 기억해서 망정이지. 조금만 눈치가 늦었어도 틀어질 전략이었다고.","JPN":"昔のコードワードを覚えていたから良かったものの。ちょっとでも気づくのが遅れていたら作戦失敗だったわ。","ENG":"Good thing I remembered the old code words. One second slower and the whole plan would've fallen apart.","TWN":"幸好我記得舊代碼詞彙。稍微反應慢一點，策略就會出問題了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L49_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"귀찮은 일도 떠넘겨버리고, 작전을 실패하면 나한테 뭐라할 생각이었겠지, 빌어먹을.","JPN":"面倒ごとも押しつけて、作戦が失敗したら私を責めるつもりだったんでしょうね、くそ。","ENG":"I get all the annoying jobs dumped on me, and if it fails, I bet they planned to blame me.","TWN":"把麻煩的事情都推給我，作戰失敗了就打算怪我吧，真是該死。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"에휴. 내 팔자야…….","JPN":"もう、疲れた……","ENG":"Ugh. What a life...","TWN":"唉，我的命啊……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"역시, 이런 건 성미에 안 맞아.","JPN":"やっぱり、こんなの性に合わないわ。","ENG":"This sneaky cloak-and-dagger stuff really isn't my style.","TWN":"果然，這種事情不合我的性格。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"확인 완료. 그래도 경력직이라 그런지 제법 쓸만하네?","JPN":"確認完了。経験者だけあってなかなかやるじゃない。","ENG":"Confirmed. Still, not bad for a veteran. You're more useful than I expected.","TWN":"確認完成。果然是有經驗的人，還挺有用的呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아무렴. 네가 무대포 방식으로 밀어붙인 게 어디 한둘이니?","JPN":"当たり前よ。あなたの無茶が多すぎたおかげでね。","ENG":"Of course. How many times have you rushed into things headfirst and left me to clean up?","TWN":"當然。你用蠻幹的方式推進的事情可不止一兩件吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"본부 쪽 트래픽이 염탐 당한 시점에서 개인 디바이스를 활용하자는 건 이해하겠는데.","JPN":"本部のトラフィックが見られてる時点で、個人デバイスを活用しようってことはわかるけど。","ENG":"I get using personal devices once HQ traffic's compromised, but...","TWN":"總部的流量被監視時，利用個人設備是可以理解的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"까딱하면 전부 나가리 될 뻔했다고.","JPN":"一歩間違ってたら全部台無しだったわよ。","ENG":"One slip and this whole operation would've been done for.","TWN":"差點就全完蛋了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"글쎄? 딱히 내 머릿속에서 나온 작전은 아니라 모르겠네.","JPN":"さあ？　別に、私の頭から出た作戦じゃないからわからないわ。","ENG":"Hey, don't look at me. This wasn't even my plan.","TWN":"嗯？這不是我腦子裡想出來的計畫，所以我不太清楚。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"안 그래, <color=#ffd34c>단장?</color>","JPN":"そうでしょう、<color=#ffd34c>団長？</color>","ENG":"Right, <color=#ffd34c>Captain?</color>","TWN":"你說對嗎，<color=#ffd34c>團長？</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다, 메데이아 경. 상황이 급하다지만 무리한 부탁을 드렸군요.","JPN":"申し訳ありません、メデイア卿。一刻を争っているとはいえ、無理なお願いをしてしまって。","ENG":"Apologies, Dame Medea. I know it was a reckless request, but the situation is urgent.","TWN":"抱歉，美狄亞。雖然情況緊急，但還是給你添麻煩了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"예. 진짜 무리한 부탁이죠? 설마 카란티시르가 이런 방식에 당해줄 거라고 생각하는 건 아니죠?","JPN":"ええ。本当に無理なお願いでしたわ。まさか、カランティシルがこんなやり方に引っかかってくれると思っているわけではないでしょうね？","ENG":"You're seriously asking this? Do you really think someone like Carantisir will fall for something this cheap?","TWN":"是的。這確實是個過分的請求吧？難道你真的認為卡蘭堤西爾會被這種方式擊敗嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"속진 않아도 당해줄 겁니다. 레드시프트의 목적은 열두 무구의 별빛을 모으는데 있으니까요.","JPN":"騙されなくても、引っかかってはくれるはずです。レッドシフトの目的は12武具の星の光を集めることなので。","ENG":"He won't fall for it, but he'll take the bait. Red Shift's goal is to gather the starlight of all twelve Armaments.","TWN":"雖然不會輕易上當，但我會配合。紅移的目標是收集十二聖遺物的星光。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"레드시프트의 다른 단원들이 움직이지 않는 것이 자의인지 타의인지 알 수 없으나.","JPN":"レッドシフトの他の団員たちに動きがないのが、自分たちの意志なのかまではまだわかりませんが。","ENG":"Whether the other Red Shift members are inactive by choice or force, I don't know.","TWN":"無法確定紅移的其他成員是否是自願不行動的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저희로 하여금 승산을 느끼게 하여 전장에 유도하는 것이 카란티시르 경의 작전이라면, 그걸 이용할 뿐입니다.","JPN":"私たちに勝算があると勘違いさせ、戦場におびき寄せることがカランティシル卿の作戦なら、それを利用するだけです。","ENG":"But if drawing us into battle is part of Carantisir's plan, then we're just flipping the script on him.","TWN":"如果卡蘭堤西爾的作戰計畫是讓我們感受到勝利的希望並引導我們進入戰場，那我們就利用這一點吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그에게 중요한 건 저희가 합류하는 방식이 아닌 합류했다는 결과니까요.","JPN":"彼に重要なのは私たちが合流する方法ではなく、合流したという結果ですから。","ENG":"He doesn't care how we join, but only that we join.","TWN":"對他來說，重要的不是我們加入的方式，而是加入的結果。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……뭐, 그냥 투정 좀 부려봤을 뿐이에요.","JPN":"……まあ、少し愚痴を言ってみただけですわ。","ENG":"...Fine. Just had to vent a little.","TWN":"……我就說說而已嘛。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"애초에 양쪽 상황을 전부 파악하고 있는 건 저밖에 없으니, 이해 못할 건 없답니다?","JPN":"そもそも両方の状況をすべて把握しているのは私しかいませんし、理解できないこともありません。","ENG":"After all, I'm the only one with eyes on both sides of this mess. Can't say I don't get it.","TWN":"我當然知道，畢竟我是最清楚雙方情況的！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐래. 그냥 네가 다루기 편한 거겠지.","JPN":"何言ってるの。単にあなたが扱いやすいだけ。","ENG":"Oh please. You just like being in control.","TWN":"說什麼呢。只是你覺得方便而已吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"줄리아야. 세상 모든 사람들이 너처럼 편협한 행동을 저지르진 않는단다?","JPN":"ジュリア。世の中の人はあなたのように視野の狭い真似はしないわよ？","ENG":"Julia, not everyone's as narrow-minded as you, you know.","TWN":"茱莉亞，不是所有人都像你這樣心胸狹窄喔？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아뇨. 그저…….","JPN":"いいえ。ただ……","ENG":"No, I just...","TWN":"不，只是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"두분께서 사이가 좋아, 작전 수행이 원활하지 않을까 싶었습니다.","JPN":"お2人の仲がいいので、作戦がうまく行くだろうと思いました。","ENG":"I figured, since you two get along, the mission would go smoothly.","TWN":"兩位關係不錯，執行任務應該會很順利吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하?","JPN":"はあ？","ENG":"...Huh?","TWN":"下？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"미쳤니? 내가, 얘랑?","JPN":"本気？　私と、こいつが？","ENG":"Are you insane?! Me, get along with her?","TWN":"你瘋了嗎？我和她？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……어쨌든 메데이아 경께서는 지정된 좌표에서 저희와 합류해주시기 바랍니다.","JPN":"……とにかく、メデイア卿は指定された座標で私たちと合流してください。","ENG":"...In any case, please rendezvous with us at the designated coordinates, Dame Medea.","TWN":"……無論如何，美狄亞請在指定座標與我們會合。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"상황에 맞춰 유동적으로 움직여야 하니 서둘러 움직이죠.","JPN":"状況に合わせて流動的に動く必要があるので、急ぎましょう。","ENG":"We need to move quickly and adapt to the situation as it develops.","TWN":"要根據情況靈活行動，所以趕緊行動吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어영부영 넘어가는 것 같지만, 좋아요.","JPN":"適当に誤魔化された気がするけど、いいですわ。","ENG":"Ugh, fine. I guess we're just breezing past all that.","TWN":"雖然看起來好像是隨便應付過去的，但我喜歡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그게 <color=#ffd34c>단장</color> 명령이라면, 따라야죠.","JPN":"それが<color=#ffd34c>団長</color>の命令なら、従います。","ENG":"If it's an order from <color=#ffd34c>Captain</color>, I'll follow it.","TWN":"如果那是<color=#ffd34c>團長</color>的命令，我當然要服從。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래도 아쉽네~. 모처럼 카란티시르와 한판 붙게 되는 줄 알았는데 말이야.","JPN":"でも残念ね～、せっかくカランティシルと戦うことになると思ってたのに。","ENG":"Still, bit of a shame. I was hoping for a proper throwdown with Carantisir.","TWN":"還是有點遺憾呢～本以為能和卡蘭堤西爾來一場較量呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"굳이 어려운 길로 돌아가는 걸 보면 에리어스란 애가 어지간히도 소중한가 봐?","JPN":"わざと難しい道を選ぶなんて、アリウスって子がそれくらい大事なのかしらね？","ENG":"But I guess this detour means that Arius kid is really important to you, huh?","TWN":"看你特意繞遠路，看來埃里奧斯對你來說相當重要吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"에리어스 경이 아니라도 같은 길을 택했을 겁니다.","JPN":"アリウス卿でなくても、同じ道を選んだはずです。","ENG":"Even if it weren't Dame Arius, I would've made the same choice.","TWN":"即使不是埃里奧斯卿，我也會選擇同樣的道路。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"피로 얼룩져진 승리를 택해서야, 레드시프트와 다를 게 없어요.","JPN":"血まみれの勝利を選択しては、レッドシフトと何ら変わりありません。","ENG":"If we chase victory soaked in blood, we're no different from Red Shift.","TWN":"選擇被鮮血染紅的勝利，和紅移沒有什麼不同。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"흐응~. 그래?","JPN":"ふーん、そう？","ENG":"Hmm... Is that so?","TWN":"唔呼～是嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"확실히 클리파 차원이 연결되었던 곳인 만큼 안전을 가하는 것도 나쁘진 않겠지.","JPN":"確かにあそこはクリファ次元が繋がっていたところだから、慎重に行くのも悪くないわね。","ENG":"Still, it's not a bad idea to secure the area. Especially with a Qlipha Dimension connected there.","TWN":"確實，既然是連接到逆卡巴拉次元的地方，確保安全也不壞。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"상대가 카란티시르라면 분명 이상한 함정을 파놨을 테니까.","JPN":"相手がカランティシルなら、きっとおかしな罠を用意してるはずだろうし。","ENG":"Knowing Carantisir, he's definitely laid a trap or two.","TWN":"如果對手是卡蘭堤西爾，肯定會設置一些奇怪的陷阱。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"AUTOMATA_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>목표지점의 위상좌표 분석 완료.</color>","JPN":"<color=#ffd34c>目標地点の位相座標分析完了。</color>","ENG":"<color=#ffd34c>Analysis of the destination's spatial coordinates is complete.</color>","TWN":"<color=#ffd34c>目標地點的位置座標分析完成。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L49_1","type":"dialog","speaker":"AUTOMATA_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>현 시간부로 지정 좌표 출력 및 시각 자료로의 변환이 가능합니다.</color>","JPN":"<color=#ffd34c>現時点から指定座標の出力および視覚資料への転換ができます。</color>","ENG":"<color=#ffd34c>Coordinates are now available for output and visual mapping.</color>","TWN":"<color=#ffd34c>從現在開始，可以輸出指定座標並轉換為視覺資料。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"대략적인 준비는 끝났으니 시작하죠.","JPN":"だいたいの準備は終わりましたので、始めましょう。","ENG":"Preparation's mostly done. Let's begin.","TWN":"大致準備就緒，開始吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"남은 건, 그들과의 정면승부입니다.","JPN":"彼らとの真っ向勝負だけが残っています。","ENG":"Now all that's left is to face them head-on.","TWN":"剩下的就是與他們的正面交鋒了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};